sp_angular_provider.script:
function scmBreadcrumbsManager($rootScope) {
    "use strict";

    const EVENT_NAME = "scm-navigation-breadcrumbs_set";
    var currentBreadcrumbs = [];

    function normalize(breadcrumbs) {
        if (!Array.isArray(breadcrumbs)) {
            return [];
        }

        return breadcrumbs
            .filter(function (item) {
                return !!item;
            })
            .map(function (item) {
                return {
                    title: String(item.title || ""),
                    link: String(item.link || "#"),
                    icon: item.icon ? String(item.icon) : "",
                };
            });
    }

    function set(breadcrumbs) {
        currentBreadcrumbs = normalize(breadcrumbs);
        $rootScope.$broadcast(EVENT_NAME, currentBreadcrumbs);
    }

    function get() {
        return currentBreadcrumbs.slice();
    }

    return {
        set: set,
        get: get,
    };
}
